+#[allow(clippy::too_many_arguments)]
+fn build_node(
+    plan: &PlanDag,
+    runtime: &mut LabRuntime,
+    region: RegionId,
+    handles: &mut Vec<Option<SharedHandle<NodeValue>>>,
+    oracle: &mut LoserDrainOracle,
+    races: &mut Vec<RaceInfo>,
+    winners: &Arc<Mutex<HashMap<u64, TaskId>>>,
+    id: PlanId,
